def range_summary(nums):
    if not nums:
        return ''
    sorted_nums = sorted(set(nums))
    result = []
    start, current = sorted_nums[0], sorted_nums[0]
    for i in range(1, len(sorted_nums)):
        if sorted_nums[i] == current + 1:
            continue
        elif sorted_nums[i] > current + 1:
            result.append(f'{start}-{current}')
            start = sorted_nums[i]
    result.append(f'{start}-{sorted_nums[-1]}') if sorted_nums[-1] != start else result.append(str(sorted_nums[-1]))
    return ', '.join(result)
